#!/usr/bin/env Rscript

# Dataset 1: final thesis plots
#
# This script reads the outputs generated by
# dataset1_filtered_diet_ml_pipeline.py and creates:
#   1. ROC-AUC distribution across the five repeated splits
#   2. Mean ROC curve for the combined diet-taxa SVM
#   3. Pooled confusion matrix for the combined diet-taxa SVM
#   4. Split-specific SVM coefficient plot
#
# Usage:
# Rscript src/dataset1_final_plots.R \
#   results/dataset1 \
#   results/dataset1/plots

required_packages <- c("dplyr", "ggplot2", "pROC", "patchwork")

missing_packages <- required_packages[
  !vapply(required_packages, requireNamespace, logical(1), quietly = TRUE)
]

if (length(missing_packages) > 0) {
  stop(
    "Missing R package(s): ",
    paste(missing_packages, collapse = ", "),
    ". Install them before running this script."
  )
}

library(dplyr)
library(ggplot2)
library(pROC)
library(patchwork)


# =============================================================================
# Paths
# =============================================================================

args <- commandArgs(trailingOnly = TRUE)

results_dir <- if (length(args) >= 1) {
  args[[1]]
} else {
  file.path("results", "dataset1")
}

plot_dir <- if (length(args) >= 2) {
  args[[2]]
} else {
  file.path(results_dir, "plots")
}

classification_file <- file.path(
  results_dir,
  "classification_results_all_splits.csv"
)

prediction_file <- file.path(
  results_dir,
  "svm_predictions_all_splits.csv"
)

coefficient_file <- file.path(
  results_dir,
  "svm_coefficients_all_splits.csv"
)

required_files <- c(
  classification_file,
  prediction_file,
  coefficient_file
)

missing_files <- required_files[!file.exists(required_files)]

if (length(missing_files) > 0) {
  stop(
    "Required input file(s) not found:\n",
    paste(missing_files, collapse = "\n")
  )
}

dir.create(plot_dir, recursive = TRUE, showWarnings = FALSE)


# =============================================================================
# Helpers
# =============================================================================

theme_thesis_clean <- function(base_size = 13) {
  theme_classic(base_size = base_size) +
    theme(
      plot.title = element_text(
        face = "bold",
        size = base_size + 1,
        hjust = 0.5
      ),
      axis.title = element_text(size = base_size),
      axis.text = element_text(size = base_size - 1),
      legend.title = element_blank(),
      legend.background = element_blank(),
      plot.caption = element_blank(),
      strip.background = element_blank(),
      strip.text = element_text(face = "bold"),
      axis.line = element_line(linewidth = 0.5),
      axis.ticks = element_line(linewidth = 0.4)
    )
}


save_plot_pair <- function(
  plot_object,
  file_stem,
  width,
  height
) {
  ggsave(
    filename = file.path(plot_dir, paste0(file_stem, ".pdf")),
    plot = plot_object,
    width = width,
    height = height,
    units = "in"
  )

  ggsave(
    filename = file.path(plot_dir, paste0(file_stem, ".png")),
    plot = plot_object,
    width = width,
    height = height,
    units = "in",
    dpi = 600
  )
}


require_columns <- function(data, required, data_name) {
  missing <- setdiff(required, names(data))

  if (length(missing) > 0) {
    stop(
      data_name,
      " is missing required column(s): ",
      paste(missing, collapse = ", ")
    )
  }
}


# =============================================================================
# Read outputs from the Python pipeline
# =============================================================================

classification_results <- read.csv(
  classification_file,
  check.names = FALSE,
  stringsAsFactors = FALSE
)

svm_predictions <- read.csv(
  prediction_file,
  check.names = FALSE,
  stringsAsFactors = FALSE
)

svm_coefficients <- read.csv(
  coefficient_file,
  check.names = FALSE,
  stringsAsFactors = FALSE
)

require_columns(
  classification_results,
  c("Split", "Input features", "Model", "ROC-AUC"),
  "Classification-results file"
)

require_columns(
  svm_predictions,
  c("Split", "y_true", "y_pred", "score"),
  "SVM-prediction file"
)

require_columns(
  svm_coefficients,
  c(
    "Split",
    "Feature ID",
    "Feature name",
    "Feature group",
    "Coefficient",
    "Rank by absolute coefficient",
    "Ranked in top 20"
  ),
  "SVM-coefficient file"
)


# =============================================================================
# Plot 1: ROC-AUC across the five repeated splits
# =============================================================================

model_colours <- c(
  "LR" = "#4C78A8",
  "SVM" = "#F58518",
  "RF" = "#54A24B",
  "BRF" = "#B279A2"
)

auc_data <- classification_results %>%
  filter(`Input features` == "Diet + taxa") %>%
  mutate(
    Model = factor(
      Model,
      levels = c("LR", "SVM", "RF", "BRF")
    )
  )

if (nrow(auc_data) == 0) {
  stop("No combined diet-taxa classification results were found.")
}

auc_plot <- ggplot(
  auc_data,
  aes(
    x = Model,
    y = `ROC-AUC`,
    fill = Model
  )
) +
  geom_boxplot(
    width = 0.55,
    outlier.shape = NA,
    linewidth = 0.6,
    alpha = 0.75
  ) +
  geom_jitter(
    aes(colour = Model),
    width = 0.08,
    size = 2.5,
    alpha = 0.9
  ) +
  stat_summary(
    fun = mean,
    geom = "point",
    shape = 23,
    size = 3.2,
    fill = "white",
    colour = "black"
  ) +
  geom_hline(
    yintercept = 0.5,
    linetype = "dashed",
    linewidth = 0.5,
    colour = "grey40"
  ) +
  scale_fill_manual(values = model_colours) +
  scale_colour_manual(values = model_colours) +
  coord_cartesian(ylim = c(0, 1)) +
  labs(
    title = "Model ROC-AUC Across Five Repeated Stratified Splits",
    x = "Classifier",
    y = "ROC-AUC"
  ) +
  theme_thesis_clean() +
  theme(
    axis.text.x = element_text(angle = 20, hjust = 1),
    legend.position = "none"
  )

save_plot_pair(
  auc_plot,
  "01_Model_AUC_Across_Five_Repeated_Splits",
  width = 7,
  height = 5
)


# =============================================================================
# Plot 2: Mean ROC curve for the combined SVM
# =============================================================================

svm_predictions <- svm_predictions %>%
  mutate(Split = as.integer(Split))

fpr_grid <- seq(0, 1, length.out = 501)

roc_by_split <- svm_predictions %>%
  group_by(Split) %>%
  group_modify(
    ~ {
      roc_object <- pROC::roc(
        response = .x$y_true,
        predictor = .x$score,
        levels = c(0, 1),
        direction = "<",
        quiet = TRUE
      )

      roc_points <- data.frame(
        FPR = 1 - roc_object$specificities,
        TPR = roc_object$sensitivities
      ) %>%
        group_by(FPR) %>%
        summarise(
          TPR = max(TPR),
          .groups = "drop"
        ) %>%
        arrange(FPR)

      data.frame(
        FPR = fpr_grid,
        TPR = approx(
          x = roc_points$FPR,
          y = roc_points$TPR,
          xout = fpr_grid,
          rule = 2
        )$y
      )
    }
  ) %>%
  ungroup()

mean_roc <- roc_by_split %>%
  group_by(FPR) %>%
  summarise(
    TPR = mean(TPR, na.rm = TRUE),
    .groups = "drop"
  )

roc_plot <- ggplot(
  mean_roc,
  aes(x = FPR, y = TPR)
) +
  geom_step(
    linewidth = 1.15,
    colour = "#F58518"
  ) +
  geom_abline(
    intercept = 0,
    slope = 1,
    linetype = "dashed",
    linewidth = 0.5,
    colour = "grey50"
  ) +
  coord_equal(
    xlim = c(0, 1),
    ylim = c(0, 1)
  ) +
  labs(
    title = "Mean ROC Curve – SVM Model",
    x = "False positive rate",
    y = "True positive rate"
  ) +
  theme_thesis_clean()

save_plot_pair(
  roc_plot,
  "02_Mean_ROC_Curve_SVM_Model",
  width = 5.5,
  height = 5.5
)


# =============================================================================
# Plot 3: Pooled confusion matrix for the combined SVM
# =============================================================================

confusion_data <- svm_predictions %>%
  mutate(
    True_label = ifelse(
      y_true == 1,
      "Depressive",
      "Healthy"
    ),
    Predicted_label = ifelse(
      y_pred == 1,
      "Depressive",
      "Healthy"
    )
  ) %>%
  count(
    True_label,
    Predicted_label,
    name = "n"
  ) %>%
  group_by(True_label) %>%
  mutate(
    row_percent = 100 * n / sum(n),
    label = paste0(
      n,
      "\n",
      sprintf("%.1f", row_percent),
      "%"
    )
  ) %>%
  ungroup()

all_cells <- expand.grid(
  True_label = c("Healthy", "Depressive"),
  Predicted_label = c("Healthy", "Depressive"),
  stringsAsFactors = FALSE
)

confusion_data <- all_cells %>%
  left_join(
    confusion_data,
    by = c("True_label", "Predicted_label")
  ) %>%
  mutate(
    n = ifelse(is.na(n), 0, n),
    row_percent = ifelse(
      is.na(row_percent),
      0,
      row_percent
    ),
    label = ifelse(
      is.na(label),
      "0\n0.0%",
      label
    ),
    True_label = factor(
      True_label,
      levels = c("Healthy", "Depressive")
    ),
    Predicted_label = factor(
      Predicted_label,
      levels = c("Healthy", "Depressive")
    )
  )

confusion_plot <- ggplot(
  confusion_data,
  aes(
    x = Predicted_label,
    y = True_label,
    fill = n
  )
) +
  geom_tile(
    colour = "white",
    linewidth = 0.9
  ) +
  geom_text(
    aes(label = label),
    size = 5,
    fontface = "bold"
  ) +
  scale_fill_gradient(
    low = "#F7FBFF",
    high = "#4C78A8"
  ) +
  labs(
    title = "Pooled Confusion Matrix – SVM Model",
    x = "Predicted label",
    y = "True label",
    fill = "Test instances"
  ) +
  theme_thesis_clean() +
  theme(
    panel.border = element_rect(
      colour = "black",
      fill = NA,
      linewidth = 0.6
    ),
    legend.position = "right"
  )

save_plot_pair(
  confusion_plot,
  "03_Pooled_Confusion_Matrix_SVM_Model",
  width = 5.5,
  height = 4.8
)


# =============================================================================
# Plot 4: Split-specific SVM coefficients
# =============================================================================

top_n <- 20
minimum_splits <- 2

coefficient_data <- svm_coefficients %>%
  mutate(
    Split = as.integer(Split),
    In_top20_this_split = tolower(
      as.character(`Ranked in top 20`)
    ) %in% c("true", "1")
  )

feature_frequency <- coefficient_data %>%
  group_by(
    `Feature ID`,
    `Feature name`,
    `Feature group`
  ) %>%
  summarise(
    Splits_in_top20 = sum(
      In_top20_this_split,
      na.rm = TRUE
    ),
    Splits_present_in_model = n_distinct(Split),
    .groups = "drop"
  ) %>%
  filter(Splits_in_top20 >= minimum_splits)

if (nrow(feature_frequency) == 0) {
  stop(
    "No features were ranked in the top ",
    top_n,
    " in at least ",
    minimum_splits,
    " splits."
  )
}

coefficient_plot_data <- coefficient_data %>%
  inner_join(
    feature_frequency,
    by = c(
      "Feature ID",
      "Feature name",
      "Feature group"
    )
  ) %>%
  filter(In_top20_this_split) %>%
  mutate(
    Feature_label = paste0(
      `Feature name`,
      "\n(",
      Splits_in_top20,
      "/5)"
    )
  )

feature_order <- coefficient_plot_data %>%
  distinct(
    `Feature ID`,
    Feature_label,
    Splits_in_top20,
    `Feature group`
  ) %>%
  arrange(
    desc(Splits_in_top20),
    `Feature group`,
    Feature_label
  ) %>%
  pull(Feature_label)

coefficient_plot_data$Feature_label <- factor(
  coefficient_plot_data$Feature_label,
  levels = feature_order
)

coefficient_plot_data <- coefficient_plot_data %>%
  mutate(
    Feature_x = as.numeric(Feature_label),
    Split_offset = case_when(
      Split == 1 ~ -0.18,
      Split == 2 ~ -0.09,
      Split == 3 ~  0.00,
      Split == 4 ~  0.09,
      Split == 5 ~  0.18,
      TRUE ~ 0.00
    ),
    Plot_x = Feature_x + Split_offset
  )

feature_levels <- levels(
  coefficient_plot_data$Feature_label
)

base_colours <- setNames(
  hcl.colors(
    length(feature_levels),
    palette = "Dynamic"
  ),
  feature_levels
)

column_colours <- setNames(
  grDevices::adjustcolor(
    base_colours,
    alpha.f = 0.30
  ),
  feature_levels
)

coefficient_plot_data <- coefficient_plot_data %>%
  mutate(
    Square_colour = base_colours[
      as.character(Feature_label)
    ]
  )

column_data <- coefficient_plot_data %>%
  group_by(Feature_label, Feature_x) %>%
  summarise(
    ymin = min(Coefficient, na.rm = TRUE),
    ymax = max(Coefficient, na.rm = TRUE),
    .groups = "drop"
  ) %>%
  mutate(
    xmin = Feature_x - 0.23,
    xmax = Feature_x + 0.23,
    Column_colour = column_colours[
      as.character(Feature_label)
    ],
    Line_colour = base_colours[
      as.character(Feature_label)
    ]
  )

y_data_min <- min(column_data$ymin, na.rm = TRUE)
y_data_max <- max(column_data$ymax, na.rm = TRUE)
y_range <- y_data_max - y_data_min

if (y_range == 0) {
  y_range <- 1
}

y_plot_min <- y_data_min - 0.08 * y_range
y_plot_max <- y_data_max + 0.08 * y_range

coefficient_plot <- ggplot() +
  geom_hline(
    yintercept = 0,
    linetype = "dashed",
    linewidth = 0.5,
    colour = "grey45"
  ) +
  geom_rect(
    data = column_data,
    aes(
      xmin = xmin,
      xmax = xmax,
      ymin = ymin,
      ymax = ymax,
      fill = Column_colour
    ),
    colour = NA
  ) +
  geom_segment(
    data = column_data,
    aes(
      x = Feature_x,
      xend = Feature_x,
      y = ymin,
      yend = ymax,
      colour = Line_colour
    ),
    linewidth = 0.7,
    alpha = 0.75
  ) +
  geom_point(
    data = coefficient_plot_data,
    aes(
      x = Plot_x,
      y = Coefficient,
      fill = Square_colour
    ),
    shape = 22,
    size = 7.2,
    colour = "black",
    stroke = 0.5
  ) +
  geom_text(
    data = coefficient_plot_data,
    aes(
      x = Plot_x,
      y = Coefficient,
      label = Split
    ),
    size = 3.2,
    fontface = "bold",
    colour = "black"
  ) +
  scale_fill_identity() +
  scale_colour_identity() +
  scale_x_continuous(
    breaks = seq_along(feature_levels),
    labels = feature_levels,
    limits = c(
      0.5,
      length(feature_levels) + 0.5
    ),
    expand = expansion(
      mult = c(0.01, 0.02)
    )
  ) +
  coord_cartesian(
    ylim = c(y_plot_min, y_plot_max),
    clip = "off"
  ) +
  labs(
    title = "SVM Coefficients Across Five Repeated Splits",
    x = "Feature",
    y = "SVM coefficient"
  ) +
  theme_thesis_clean() +
  theme(
    axis.text.x = element_text(
      angle = 45,
      hjust = 1,
      vjust = 1,
      size = 10
    ),
    legend.position = "none",
    plot.margin = margin(10, 10, 5, 10)
  )

split_key_data <- data.frame(
  Split = 1:5,
  x = 1:5,
  y_square = 1.0,
  y_text = 0.18,
  label = paste("Split", 1:5)
)

split_key_plot <- ggplot(
  split_key_data,
  aes(x = x, y = y_square)
) +
  geom_point(
    shape = 22,
    size = 4.8,
    fill = "grey78",
    colour = "black",
    stroke = 0.5
  ) +
  geom_text(
    aes(label = Split),
    size = 2.4,
    fontface = "bold",
    colour = "black"
  ) +
  geom_text(
    aes(
      y = y_text,
      label = label
    ),
    size = 2.8,
    colour = "black"
  ) +
  coord_cartesian(
    xlim = c(0.5, 5.5),
    ylim = c(0, 1.25),
    clip = "off"
  ) +
  theme_void() +
  theme(
    plot.margin = margin(0, 0, 0, 35)
  )

bottom_row <- split_key_plot +
  plot_spacer() +
  plot_layout(widths = c(2.8, 8))

final_coefficient_plot <- coefficient_plot /
  bottom_row +
  plot_layout(heights = c(14, 1.8))

save_plot_pair(
  final_coefficient_plot,
  "04_SVM_Coefficients_Across_Five_Repeated_Splits",
  width = 11,
  height = 7.2
)


# =============================================================================
# Done
# =============================================================================

cat("Final Dataset 1 plots saved in:\n")
cat(plot_dir, "\n")
